catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
	if (isLoading || newValue == '') {
		return;
	}

	informationAddress('pesquisaCEP', newValue);

	function informationAddress(metodo, cep) {
		var gaRua = new GlideAjax('CepIntegrationAjax');
		gaRua.addParam('sysparm_name', metodo);
		gaRua.addParam('sysparm_cep', cep);
		gaRua.getXML(callback);

		function callback(response) {
			var answer = response.responseXML.documentElement.getAttribute("answer");

			if (answer) {
				var endereco = JSON.parse(answer);
				g_form.setValue('endereco', endereco.logradouro);
				g_form.setValue('bairro', endereco.bairro);
				g_form.setValue('cidade', endereco.localidade);
				g_form.setValue('estado', endereco.estado);

			} else {
				g_form.addErrorMessage("CEP inválido.");	
			}
		}
	}
}
